// oauth-config.js
const OAuthConfig = {
  authorizationEndpoint: 'https://your-auth-server.com/oauth/authorize',
  tokenEndpoint: 'https://your-auth-server.com/oauth/token',
  clientId: 'your-client-id',
  redirectUri: window.location.origin + '/callback',
  scope: 'read write',
  responseType: 'code'
};

// pkce-utils.js
function generateRandomString(length) {
  const charset = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~';
  const randomValues = new Uint8Array(length);
  crypto.getRandomValues(randomValues);
  return Array.from(randomValues)
    .map(v => charset[v % charset.length])
    .join('');
}

async function generateCodeChallenge(codeVerifier) {
  const encoder = new TextEncoder();
  const data = encoder.encode(codeVerifier);
  const hash = await crypto.subtle.digest('SHA-256', data);
  return base64UrlEncode(hash);
}

function base64UrlEncode(arrayBuffer) {
  const bytes = new Uint8Array(arrayBuffer);
  let binary = '';
  for (let i = 0; i < bytes.byteLength; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary)
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=/g, '');
}

// token-storage.js
const TokenStorage = {
  setTokens(accessToken, refreshToken, expiresIn) {
    const expiresAt = Date.now() + (expiresIn * 1000);
    localStorage.setItem('access_token', accessToken);
    localStorage.setItem('expires_at', expiresAt.toString());
    if (refreshToken) {
      localStorage.setItem('refresh_token', refreshToken);
    }
  },

  getAccessToken() {
    return localStorage.getItem('access_token');
  },

  getRefreshToken() {
    return localStorage.getItem('refresh_token');
  },

  isTokenExpired() {
    const expiresAt = localStorage.getItem('expires_at');
    if (!expiresAt) return true;
    return Date.now() >= parseInt(expiresAt);
  },

  clearTokens() {
    localStorage.removeItem('access_token');
    localStorage.removeItem('refresh_token');
    localStorage.removeItem('expires_at');
    localStorage.removeItem('code_verifier');
    localStorage.removeItem('state');
  },

  setCodeVerifier(verifier) {
    localStorage.setItem('code_verifier', verifier);
  },

  getCodeVerifier() {
    return localStorage.getItem('code_verifier');
  },

  setState(state) {
    localStorage.setItem('state', state);
  },

  getState() {
    return localStorage.getItem('state');
  }
};

// oauth-service.js
const OAuthService = {
  async initiateLogin() {
    const state = generateRandomString(32);
    const codeVerifier = generateRandomString(128);
    const codeChallenge = await generateCodeChallenge(codeVerifier);

    TokenStorage.setState(state);
    TokenStorage.setCodeVerifier(codeVerifier);

    const params = new URLSearchParams({
      response_type: OAuthConfig.responseType,
      client_id: OAuthConfig.clientId,
      redirect_uri: OAuthConfig.redirectUri,
      scope: OAuthConfig.scope,
      state: state,
      code_challenge: codeChallenge,
      code_challenge_method: 'S256'
    });

    window.location.href = `${OAuthConfig.authorizationEndpoint}?${params.toString()}`;
  },

  async handleCallback() {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    const state = urlParams.get('state');
    const error = urlParams.get('error');

    if (error) {
      throw new Error(`OAuth error: ${error}`);
    }

    if (!code) {
      throw new Error('No authorization code received');
    }

    const storedState = TokenStorage.getState();
    if (state !== storedState) {
      throw new Error('State mismatch - possible CSRF attack');
    }

    const codeVerifier = TokenStorage.getCodeVerifier();
    if (!codeVerifier) {
      throw new Error('Code verifier not found');
    }

    await this.exchangeCodeForToken(code, codeVerifier);
  },

  async exchangeCodeForToken(code, codeVerifier) {
    const params = new URLSearchParams({
      grant_type: 'authorization_code',
      code: code,
      redirect_uri: OAuthConfig.redirectUri,
      client_id: OAuthConfig.clientId,
      code_verifier: codeVerifier
    });

    const response = await fetch(OAuthConfig.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: params.toString()
    });

    if (!response.ok) {
      const errorData = await response.json();
      throw new Error(`Token exchange failed: ${errorData.error_description || errorData.error}`);
    }

    const data = await response.json();
    TokenStorage.setTokens(data.access_token, data.refresh_token, data.expires_in);
    TokenStorage.setState(null);
    TokenStorage.setCodeVerifier(null);

    return data;
  },

  async refreshAccessToken() {
    const refreshToken = TokenStorage.getRefreshToken();
    if (!refreshToken) {
      throw new Error('No refresh token available');
    }

    const params = new URLSearchParams({
      grant_type: 'refresh_token',
      refresh_token: refreshToken,
      client_id: OAuthConfig.clientId
    });

    const response = await fetch(OAuthConfig.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: params.toString()
    });

    if (!response.ok) {
      TokenStorage.clearTokens();
      throw new Error('Token refresh failed');
    }

    const data = await response.json();
    TokenStorage.setTokens(data.access_token, data.refresh_token, data.expires_in);

    return data;
  },

  async getValidAccessToken() {
    if (TokenStorage.isTokenExpired()) {
      try {
        await this.refreshAccessToken();
      } catch (error) {
        this.initiateLogin();
        throw error;
      }
    }
    return TokenStorage.getAccessToken();
  },

  logout() {
    TokenStorage.clearTokens();
    window.location.href = '/';
  }
};

// api-client.js
const ApiClient = {
  async request(url, options = {}) {
    const accessToken = await OAuthService.getValidAccessToken();

    const headers = {
      'Authorization': `Bearer ${accessToken}`,
      'Content-Type': 'application/json',
      ...options.headers
    };

    const response = await fetch(url, {
      ...options,
      headers
    });

    if (response.status === 401) {
      try {
        await OAuthService.refreshAccessToken();
        const newAccessToken = TokenStorage.getAccessToken();
        headers['Authorization'] = `Bearer ${newAccessToken}`;
        return await fetch(url, { ...options, headers });
      } catch (error) {
        OAuthService.initiateLogin();
        throw error;
      }
    }

    return response;
  },

  async get(url) {
    return this.request(url, { method: 'GET' });
  },

  async post(url, data) {
    return this.request(url, {
      method: 'POST',
      body: JSON.stringify(data)
    });
  },

  async put(url, data) {
    return this.request(url, {
      method: 'PUT',
      body: JSON.stringify(data)
    });
  },

  async delete(url) {
    return this.request(url, { method: 'DELETE' });
  }
};

// app.js
class App {
  constructor() {
    this.init();
  }

  init() {
    const path = window.location.pathname;

    if (path === '/callback') {
      this.handleCallback();
    } else if (this.isAuthenticated()) {
      this.renderApp();
    } else {
      this.renderLogin();
    }
  }

  isAuthenticated() {
    return TokenStorage.getAccessToken() && !TokenStorage.isTokenExpired();
  }

  async handleCallback() {
    try {
      await OAuthService.handleCallback();
      window.history.replaceState({}, document.title, '/');
      this.renderApp();
    } catch (error) {
      console.error('Callback error:', error);
      this.renderError(error.message);
    }
  }

  renderLogin() {
    document.body.innerHTML = `
      <div id="app">
        <div class="login-container">
          <h1>OAuth 2.0 Authentication</h1>
          <button id="login-btn">Login with OAuth</button>
        </div>
      </div>
    `;

    document.getElementById('login-btn').addEventListener('click', () => {
      OAuthService.initiateLogin();
    });
  }

  renderApp() {
    document.body.innerHTML = `
      <div id="app">
        <div class="app-container">
          <h1>Authenticated Application</h1>
          <button id="logout-btn">Logout</button>
          <button id="fetch-data-btn">Fetch Protected Data</button>
          <div id="data-container"></div>
        </div>
      </div>
    `;

    document.getElementById('logout-btn').addEventListener('click', () => {
      OAuthService.logout();
    });

    document.getElementById('fetch-data-btn').addEventListener('click', async () => {
      await this.fetchProtectedData();
    });
  }

  async fetchProtectedData() {
    const dataContainer = document.getElementById('data-container');
    try {
      const response = await ApiClient.get('https://api.example.com/protected-resource');
      const data = await response.json();
      dataContainer.innerHTML = `<pre>${JSON.stringify(data, null, 2)}</pre>`;
    } catch (error) {
      dataContainer.innerHTML = `<p class="error">Error: ${error.message}</p>`;
    }
  }

  renderError(message) {
    document.body.innerHTML = `
      <div id="app">
        <div class="error-container">
          <h1>Authentication Error</h1>
          <p>${message}</p>
          <button id="retry-btn">Try Again</button>
        </div>
      </div>
    `;

    document.getElementById('retry-btn').addEventListener('click', () => {
      TokenStorage.clearTokens();
      window.location.href = '/';
    });
  }
}

document.addEventListener('DOMContentLoaded', () => {
  new App();
});